import{_ as e}from"./chunks/cloudflare api token截图.cXTahxtC.js";import{_ as i}from"./chunks/查看全局令牌.BhcACLhK.js";import{_ as l,o as n,c as r,a2 as t}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Cloudflare API Token","description":"","frontmatter":{},"headers":[],"relativePath":"ms-MY/Safety/cloudflare-api-token.md","filePath":"ms-MY/Safety/cloudflare-api-token.md","lastUpdated":1781962217000}'),o={name:"ms-MY/Safety/cloudflare-api-token.md"};function d(s,a,u,p,c,h){return n(),r("div",null,[...a[0]||(a[0]=[t('<h1 id="cloudflare-api-token" tabindex="-1">Cloudflare API Token <a class="header-anchor" href="#cloudflare-api-token" aria-label="Permalink to &quot;Cloudflare API Token&quot;">​</a></h1><p>Cloudflare API credentials membolehkan ImgBed purge Cloudflare CDN cache selepas files berubah.</p><p><img src="'+e+'" alt="Cloudflare API Token settings" loading="lazy"></p><h2 id="di-mana-untuk-configure" tabindex="-1">Di Mana Untuk Configure <a class="header-anchor" href="#di-mana-untuk-configure" aria-label="Permalink to &quot;Di Mana Untuk Configure&quot;">​</a></h2><p>Buka admin panel, kemudian pergi ke:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Cloudflare API Token</span></span></code></pre></div><p>Anda perlu mengisi:</p><ul><li>Zone ID</li><li>Account email</li><li>API Key</li></ul><h2 id="fungsi-setting-ini" tabindex="-1">Fungsi Setting Ini <a class="header-anchor" href="#fungsi-setting-ini" aria-label="Permalink to &quot;Fungsi Setting Ini&quot;">​</a></h2><p>Cloudflare mungkin cache public image URLs.</p><p>Caching membuatkan image delivery lebih laju, tetapi ia juga boleh menyebabkan content lama masih kelihatan seketika selepas anda delete, block, replace atau move file.</p><p>Selepas Cloudflare API credentials dikonfigurasi, ImgBed cuba purge Cloudflare cache yang berkaitan apabila operasi tersebut selesai.</p><p>Ini berguna apabila:</p><ul><li>Anda delete image dan mahu public link berhenti berfungsi secepat mungkin.</li><li>Anda block image dan mahu visitors berhenti melihat original file.</li><li>Anda replace file dengan nama yang sama dan mahu visitors melihat version baharu lebih cepat.</li><li>Anda move atau rename files dan mahu old path cache refresh dengan cepat.</li><li>Anda menukar public access rules dan mahu public gallery atau random image cache update lebih cepat.</li></ul><h2 id="jika-dibiarkan-kosong" tabindex="-1">Jika Dibiarkan Kosong <a class="header-anchor" href="#jika-dibiarkan-kosong" aria-label="Permalink to &quot;Jika Dibiarkan Kosong&quot;">​</a></h2><p>ImgBed masih berfungsi secara normal tanpa setting ini.</p><p>Bezanya, ImgBed tidak akan actively purge Cloudflare CDN cache. Visitors mungkin terus melihat content lama sehingga Cloudflare cache expire secara semula jadi.</p><h2 id="cara-mencari-zone-id" tabindex="-1">Cara Mencari Zone ID <a class="header-anchor" href="#cara-mencari-zone-id" aria-label="Permalink to &quot;Cara Mencari Zone ID&quot;">​</a></h2><p>Zone ID ialah Cloudflare Zone ID untuk site yang digunakan oleh ImgBed domain anda.</p><ol><li>Sign in ke Cloudflare dashboard.</li><li>Buka site yang mengandungi ImgBed domain anda.</li><li>Cari <code>Zone ID</code> pada site overview page.</li><li>Copy ke field <code>Zone ID</code> dalam ImgBed.</li></ol><p>Ini ialah site Zone ID, bukan account ID.</p><h2 id="account-email" tabindex="-1">Account Email <a class="header-anchor" href="#account-email" aria-label="Permalink to &quot;Account Email&quot;">​</a></h2><p>Masukkan email address yang anda gunakan untuk sign in ke Cloudflare.</p><p>Ia mesti sepadan dengan API Key yang diberi di bawah.</p><h2 id="api-key" tabindex="-1">API Key <a class="header-anchor" href="#api-key" aria-label="Permalink to &quot;API Key&quot;">​</a></h2><p>Masukkan Cloudflare Global API Key.</p><ol><li>Sign in ke Cloudflare dashboard.</li><li>Buka profile anda.</li><li>Pergi ke API Tokens page.</li><li>Cari <code>Global API Key</code>.</li><li>View dan copy.</li><li>Paste ke field <code>API Key</code> dalam ImgBed.</li></ol><p><img src="'+i+'" alt="View global API key" loading="lazy"></p><h2 id="bila-ia-berkuat-kuasa" tabindex="-1">Bila Ia Berkuat Kuasa <a class="header-anchor" href="#bila-ia-berkuat-kuasa" aria-label="Permalink to &quot;Bila Ia Berkuat Kuasa&quot;">​</a></h2><p>Selepas mengisi field, save settings.</p><p>Perubahan file selepas itu akan cuba purge Cloudflare cache secara automatik. Operasi lama tidak dipurge secara retroaktif. Jika anda delete atau replace file sebelum setup ini, tunggu Cloudflare cache expire atau purge secara manual dalam Cloudflare.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="adakah-ini-wajib" tabindex="-1">Adakah Ini Wajib? <a class="header-anchor" href="#adakah-ini-wajib" aria-label="Permalink to &quot;Adakah Ini Wajib?&quot;">​</a></h3><p>Tidak.</p><p>Jika domain anda tidak menggunakan Cloudflare, atau anda tidak kisah dengan CDN cache delay, anda boleh biarkan kosong.</p><h3 id="adakah-wrong-credentials-akan-merosakkan-uploads" tabindex="-1">Adakah Wrong Credentials Akan Merosakkan Uploads? <a class="header-anchor" href="#adakah-wrong-credentials-akan-merosakkan-uploads" aria-label="Permalink to &quot;Adakah Wrong Credentials Akan Merosakkan Uploads?&quot;">​</a></h3><p>Biasanya tidak.</p><p>Wrong credentials hanya menghalang ImgBed daripada purge Cloudflare cache. Upload dan normal file access sepatutnya terus berfungsi.</p><h3 id="mengapa-deleted-image-masih-boleh-dibuka" tabindex="-1">Mengapa Deleted Image Masih Boleh Dibuka? <a class="header-anchor" href="#mengapa-deleted-image-masih-boleh-dibuka" aria-label="Permalink to &quot;Mengapa Deleted Image Masih Boleh Dibuka?&quot;">​</a></h3><p>Sebab paling biasa ialah Cloudflare masih menyimpan file lama dalam cache.</p><p>Dengan Cloudflare API credentials yang betul, ImgBed purge related URL cache apabila file dipadam.</p><h3 id="mengapa-masih-nampak-image-lama-selepas-replace-file" tabindex="-1">Mengapa Masih Nampak Image Lama Selepas Replace File? <a class="header-anchor" href="#mengapa-masih-nampak-image-lama-selepas-replace-file" aria-label="Permalink to &quot;Mengapa Masih Nampak Image Lama Selepas Replace File?&quot;">​</a></h3><p>Ini juga biasanya disebabkan CDN cache.</p><p>Selepas setting ini dikonfigurasi, ImgBed cuba purge old URL cache apabila file dengan nama sama dioverwrite.</p>',44)])])}const f=l(o,[["render",d]]);export{b as __pageData,f as default};
